// Load deployments from deployments.json (generated by GitHub Actions)
document.addEventListener('DOMContentLoaded', () => {
  const container = document.getElementById('deployment-list');

  fetch('deployments.json')
    .then(res => {
      if (!res.ok) throw new Error('Not found');
      return res.json();
    })
    .then(data => {
      if (!data.deployments || data.deployments.length === 0) {
        container.innerHTML = '<p class="no-deployments">No active deployments yet. Push a branch to get started.</p>';
        return;
      }

      container.innerHTML = data.deployments.map(d => {
        const isMain = d.branch === 'main';
        const statusClass = isMain ? 'live' : 'preview';
        const statusText = isMain ? 'production' : 'preview';
        const time = formatTime(d.created_on);

        return `
          <div class="deployment-item">
            <a href="${d.url}" class="deployment-branch" target="_blank" rel="noopener">${d.branch}</a>
            <div class="deployment-meta">
              <span class="deployment-status ${statusClass}">${statusText}</span>
              <span class="deployment-time">${time}</span>
            </div>
          </div>
        `;
      }).join('');
    })
    .catch(() => {
      container.innerHTML = '<p class="no-deployments">No deployment data available. Deployments will appear here after the next push to main.</p>';
    });
});

function formatTime(iso) {
  if (!iso) return '';
  const date = new Date(iso);
  const now = new Date();
  const diff = now - date;

  if (diff < 60000) return 'just now';
  if (diff < 3600000) return Math.floor(diff / 60000) + 'm ago';
  if (diff < 86400000) return Math.floor(diff / 3600000) + 'h ago';

  return date.toLocaleDateString('en-US', {
    month: 'short',
    day: 'numeric',
    year: date.getFullYear() !== now.getFullYear() ? 'numeric' : undefined
  });
}
